head.script:

		/**
		 * 화면 초기화에 필요한 로직을 수행한다.
		 */
		scwin.initScreen = function() {
			scwin.search();
		};

		/**
		 * 첨부파일 List조회
		 */
		scwin.search = function() {
			var requestData = {"dma_FileBasic": dma_FileBasic.getModifiedJSON()};
//			var requestData = {};
			var option = {action : "file/fileList.do"
		               , reqData : requestData
		               , resData : dlt_file
			           , success : "scwin.searchCallback"
			           , isShowMeg : false
		                 };			
			ajaxLib.executeAjax($p, option);	
		};

		/**
		 * 첨부파일 조회
		 */
		scwin.searchCallback = function(resBody) {
			if (dlt_file.getRowCount() > 0) {
				grd_file.setFocusedCell(0, "orginlFileNm");
			}
		};

/*		
		//첨부파일다운로드버튼		
		scwin.btn_Download_onclick = function(filePath, saveFileName, fileName){
			//다운로드 경로
			var sendUrl = filePath + "/" + saveFileName;
			fileLib.fileDownload(sendUrl, fileName);
		};
*/		

		// 셀 더블클릭 	
		scwin.grd_file_oncelldblclick  = function(row, col) {
			var atchFileId = dlt_file.getCellData( row, "atchFileId" );       	//첨부파일 ID
			var fileSn = dlt_file.getCellData( row, "fileSn" );       	//첨부파일 ID
			var filePath = dlt_file.getCellData(row, "fileSavePath");				//서버에 저장된 파일 경로
			var saveFileName = dlt_file.getCellData( row , "saveFileNm" );			//서버에 저장된 파일명
			var fileName = dlt_file.getCellData(row, "orginlFileNm");		//저장할 파일명

			if (atchFileId != null) {
				// filePath : 서버에 저장된 파일 경로
				// saveFileName : 서버에 저장된 파일명
				// fileName : 원본파일명
				var sendUrl = filePath + "/" + saveFileName;
				fileLib.fileDownload(sendUrl, fileName);
			}
		};

		/**
		 * 파일첨부
		 */
		scwin.btn_Insert_onclick = function() {
			var options = {
					title : "멀티파일 업로드", width : 800, height : 400, 
					popupParam : { closeCallbackFncName : "scwin.mutiFileUploadCallback" }
				};
			comLib.openPopup($p, "mutiFileUpload", "/ui/common/file/fileUploadPopup.xml", options);
		};

		// 팝업 CallBack 함수
		scwin.mutiFileUploadCallback = function(fileData) {
			var insertedIndex;
			for (var i=0; i<fileData.length; i++) {
				insertedIndex = dlt_file.insertRow( );

				dlt_file.setCellData( insertedIndex , dlt_file.getColumnIndex( "orginlFileNm" ) , fileData[i].localFile );
				dlt_file.setCellData( insertedIndex , dlt_file.getColumnIndex( "idvdinfoInclsYn" ) , "N" );
				dlt_file.setCellData( insertedIndex , dlt_file.getColumnIndex( "sapYn" ) , "N" );
				dlt_file.setCellData(insertedIndex, dlt_file.getColumnIndex("fileTempPath"), "[UPLOAD_PATH]" +fileData[i].file);
			}
		};
		// 저장버튼 클릭
		scwin.btn_Save_onclick = function() {
			comLib.confirm($p, "첨부파일을 저장하시겠습니까?", "saveFileBasicConfirmCallback");
		};

		// 저장처리
		scwin.saveFileBasicConfirmCallback = function() {
			var requestData = {"dlt_file" : dlt_file.getModifiedJSON() };
			var option = {action : "file/insertAtchFile.do"
			               , reqData : requestData
			               , resData : dlt_file
			               , success : "scwin.saveFileBasicCallback"
			               , isShowMeg : false
				            };			
			ajaxLib.executeAjax($p, option);
		};

		// 저장후 콜백
		scwin.saveFileBasicCallback  = function(resBody) {
			comLib.alert($p, resBody.message.code_name);
			scwin.search();
		};

	/**
	 * 엑셀다운로드	
	 */
	scwin.btn_Excel_onclick = function(){
		comLib.downloadExcel(grd_file, {fileName : "AtchFileList_Data.xlsx"}, []);
	};

/*	
	scwin.btn_FileCrypto_onclick = function() {
			var requestData = {};
			var option = {action : "test/testEncDecFile.do"
		               , reqData : requestData
		               , resData : dlt_file
			           , success : "scwin.fileCryptoCallback"
			           , isShowMeg : false
		                 };			
			ajaxLib.executeAjax($p, option);	
	};

	scwin.fileCryptoCallback = function(resBody) {
		comLib.alert($p, resBody.message.code_name);
	}
*/
	//SAP FileUpload 팝업
	scwin.btn_sapFileAttch_onclick = function() {
		var options = {
					title : "SAP 멀티파일 업로드", width : 800, height : 250, 
					popupParam : { closeCallbackFncName : "mutiFileUploadCallback" }
				};
			comLib.openPopup($p, "mutiFileUpload", "/ui/common/file/sapFileUploadPopup.xml", options);
	};
